    APA.ORIG_QTY                             AS BFR_INCM_PYMT_FACE_VAL_AMT,  -- [DRD_PHYSICAL] DRD source CCAL_REPL_OWNER.APA.ORIG_QTY /* see ETL block PRODUCT_INFORMATION in header */
    APA.ORIG_QTY                             AS BASE_POS_QTY,  -- [DRD_PHYSICAL] DRD source CCAL_REPL_OWNER.APA.ORIG_QTY /* see ETL block PRODUCT_INFORMATION in header */
