    APA.ORIG_QTY                             AS REIVS_SHR_QTY,  -- [DRD_PHYSICAL] DRD source CCAL_REPL_OWNER.APA.ORIG_QTY /* see ETL block PRODUCT_INFORMATION in header */
    APA.SCR_PRC_IN_TXN_CCY                   AS REIVS_PRC  -- [DRD_PHYSICAL] DRD source CCAL_REPL_OWNER.APA.SCR_PRC_IN_TXN_CCY /* see ETL block PRODUCT_INFORMATION in header */
FROM CCAL_REPL_OWNER.TXN t
LEFT JOIN CCAL_REPL_OWNER.APA APA ON TXN.TXN_ID = APA.EXEC_ID AND APA.exec_id = t.txn_id
LEFT JOIN CCAL_REPL_OWNER.TXN_AVY_CL TXN_AVY_CL ON TXN.TXN_ID = TXN_AVY_CL.TXN_ID (+) AND APA.EXEC_ID = TXN_AVY_CL.EXEC_ID (+) AND APA.APA_ID = TXN_AVY_CL.APA_ID (+) AND TXN_AVY_CL.txn_id = t.txn_id AND APA.apa_id = TXN_AVY_CL.apa_id
LEFT JOIN CCAL_REPL_OWNER.AVY_CL AVY_CL ON TXN_AVY_CL.AVY_CL_ID = AVY_CL.AVY_CL_ID (+) AND AVY_CL.avy_cl_id = TXN_AVY_CL.avy_cl_id
LEFT JOIN CIRD_OWNER.IMT_PD_DIM SEC_IMT_PD_DIM ON APA.PD_ID = SEC_IMT_PD_DIM.CCAL_PD_ID (+)
LEFT JOIN CIRD_OWNER.CCY_DIM SEC_CCY_DIM ON APA.STM_BASE_ISO_CCY_CODE = SEC_CCY_DIM.CCY_CD (+)
LEFT JOIN COMMON_OWNER.ACG_TP_DIM ACG_TP_DIM ON APA.ACG_TP_ID = ACG_TP_DIM.ACG_TP_ID (+) AND APA.ACG_TP_ID = ACG_TP_DIM.ACG_TP_ID
LEFT JOIN CCSI_OWNER.AR_DIM OFST_AR_DIM ON APA.OFST_AR_ID = OFST_AR_DIM.AR_ID (+)
LEFT JOIN CCAL_REPL_OWNER.CL_VAL ASSET_PACKAGE_TYPE ON APA.APA_TP_ID = ASSET_PACKAGE_TYPE.CL_VAL_ID (+)
LEFT JOIN CCAL_REPL_OWNER.CL_VAL DEBIT_CREDIT_TYPES ON APA.DB_CR_ID = DEBIT_CREDIT_TYPES.CL_VAL_ID (+)
LEFT JOIN COMMON_OWNER.CASH_POS_TP_DIM CASH_POS_TP_DIM ON APA.CASH_POS_TP_ID = CASH_POS_TP_DIM.CASH_POS_TP_ID (+) AND APA.CASH_POS_TP_ID = CASH_POS_TP_DIM.CASH_POS_TP_ID
LEFT JOIN CCAL_REPL_OWNER.CL_VAL SALE_CHARGE_RATE_TYPE ON APA.SALE_CHRG_RATE_TP_ID = SALE_CHARGE_RATE_TYPE.CL_VAL_ID (+)
LEFT JOIN CCAL_REPL_OWNER.CCAL_CIRD_PD_MAP CCAL_CIRD_PD_MAP ON APA.PD_ID = CCAL_CIRD_PD_MAP.CCAL_PD_ID (+) AND APA.pd_id = CCAL_CIRD_PD_MAP.ccal_pd_id AND CCAL_CIRD_PD_MAP.ccal_pd_id = APA.pd_id AND ap.pd_id = CCAL_CIRD_PD_MAP.ccal_pd_id
LEFT JOIN CIRD_OWNER.IMT_PD_DIM IMT_PD_DIM ON CCAL_CIRD_PD_MAP.CIRD_PD_ID = IMT_PD_DIM.CIRD_PD_ID (+) AND IMT_PD_DIM.CCAL_PD_ID = APA.PD_ID AND ap.pd_id = IMT_PD_DIM.cird_pd_id AND ap.pd_id = IMT_PD_DIM.ccal_pd_id AND CCAL_CIRD_PD_MAP.cird_pd_id = IMT_PD_DIM.cird_pd_id
LEFT JOIN CIRD_OWNER.CCY_DIM CCY_DIM ON APA.TXN_ISO_CCY_CODE = CCY_DIM.CCY_CD (+) AND APA.stm_base_iso_ccy_code = CCY_DIM.ccy_cd AND CCY_DIM.ccy_cd = APA.txn_iso_ccy_code
LEFT JOIN CCAL_REPL_OWNER.FIP FIP ON APA.APA_ID = FIP.APA_ID (+) AND FIP.apa_id = APA.apa_id
LEFT JOIN CCAL_REPL_OWNER.NNA_CGY NNA_CGY ON TXN_AVY_CL.NNA_CGY_ID = NNA_CGY.NNA_CGY_ID (+)
LEFT JOIN REFERENCE_REPL_OWNER.CCY CCY ON APA.ORIG_CCY_ID = CCY.CCY_ISO_NUM_CODE (+) AND apa.orig_ccy_id = CCY.CCY_ISO_NUM_CODE AND apa.txn_iso_ccy_code = CCY.CCY_CODE
LEFT JOIN CCAL_REPL_OWNER.CL_VAL TRANSACTION_TYPE ON TXN.TXN_TP_ID = TRANSACTION_TYPE.CL_VAL_ID (+)
LEFT JOIN CCAL_REPL_OWNER.CL_VAL TRANSACTION_SUBTYPE ON TXN.TXN_SBTP_ID = TRANSACTION_SUBTYPE.CL_VAL_ID (+)
LEFT JOIN CCAL_REPL_OWNER.CL_VAL EXECUTION_SUBTYPE ON TXN.EXEC_SBTP_ID = EXECUTION_SUBTYPE.CL_VAL_ID (+)
LEFT JOIN CCAL_REPL_OWNER.CL_VAL EXECUTION_TYPE ON TXN.EXEC_TP_ID = EXECUTION_TYPE.CL_VAL_ID (+)
LEFT JOIN COMMON_OWNER.DATE_DIM TD_DATE_DIM ON TXN.TD= TD_DATE_DIM.CAL_DT (+)
LEFT JOIN COMMON_OWNER.DATE_DIM SD_DATE_DIM ON TXN.SD = SD_DATE_DIM.CAL_DT (+) AND t.td = SD_DATE_DIM.cal_dt
